module RefModule (
    input wire clk,
    input wire rst,
    input wire load,
    input wire [3:0] preset,
    output reg [3:0] count
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (rst) begin
            count <= 4'b0000;
        end else if (load) begin
            count <= preset;
        end else if (count > 0) begin
            count <= count - 1;
        end else begin
            count <= preset;
        end
    end
endmodule
